<!-- ===== Dotted World Map | Use Your Own SVG ===== -->
<style>
  #wmap-section {
    width: 100%;
    background: #fff;
    overflow: hidden;
    padding: 40px 0 60px;
  }

  #wmap-inner {
    position: relative;
    width: 100%;
    max-width: 1360px;
    margin: 0 auto;
  }

  /* Your SVG fills the container */
  #wmap-inner svg,
  #wmap-inner img {
    display: block;
    width: 100%;
    height: auto;
  }

  /* ── Marker base ── */
  .wmap-marker {
    position: absolute;
    transform: translate(-50%, -50%);
    cursor: pointer;
    z-index: 20;
  }

  /* Default: small colored dot */
  .wmap-dot {
    width: 9px;
    height: 9px;
    border-radius: 50%;
    transition: opacity 0.2s;
  }

  /* Pin — hidden by default */
  .wmap-pin {
    position: absolute;
    top: -40px;
    left: 50%;
    transform: translateX(-50%) translateY(50%) scale(0);
    transform-origin: bottom center;
    transition: transform 0.2s ease;
    pointer-events: none;    width: 20px;height: 20px;
  }

  .wmap-marker:hover .wmap-dot {
    opacity: 0;
  }
  .wmap-marker:hover .wmap-pin {
    transform: translateX(-50%) translateY(50%) scale(1);
  }

  /* Tooltip */
  .wmap-tooltip {
    position: absolute;
    bottom: calc(100% + 44px);
    left: 50%;
    transform: translateX(-50%) translateY(6px);
    background: #fff;
    border-radius: 10px;
    padding: 8px 18px 10px;
    white-space: nowrap;
    text-align: center;
    box-shadow: 0 4px 20px rgba(0,0,0,0.14);
    border: 1px solid rgba(0,0,0,0.07);
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.2s ease, transform 0.2s ease;
    min-width: 135px;
  }
  .wmap-tooltip::after {
    content: '';
    position: absolute;
    top: 100%; left: 50%;
    transform: translateX(-50%);
    border: 7px solid transparent;
    border-top-color: #fff;
  }
  .wmap-marker:hover .wmap-tooltip {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }

  .wmap-tip-country {
    display: block;
    font-size: 14px;
    font-weight: 700;
    margin-bottom: 3px;
  }
  .wmap-tip-city {
    display: block;
    font-size: 12px;
    color: #999;
  }
  .wmap-red  { color: #e84040; }
  .wmap-blue { color: #2563be; }
</style>



<script>
(function () {

  /* ============================================= */
